def kth_ordered(words, k):
    if not words or k < 1:
        return None

    # Group words by their length
    groups = {}
    max_length = 0
    for word in words:
        length = len(word)
        if length not in groups:
            groups[length] = []
        groups[length].append(word)
        max_length = max(max_length, length)

    sorted_words = []
    # Collect words from longest to shortest
    for length in range(max_length, 0, -1):
        if length in groups:
            # Sort words of equal length reverse-alphabetically
            groups[length].sort(reverse=True)
            sorted_words.extend(groups[length])

    if k <= len(sorted_words):
        return sorted_words[k-1]
    else:
        return None

# Edge case: When the input list is empty, the function returns None.
